// generar_260_enriquecimiento_y_cuidados.js
// CHIQUI Entre Señales — Enriquecimiento y entrenamiento + mejoras de
// cuidados diarios
//
// IMPORTANTE: primero corre sql_260_enriquecimiento_y_cuidados.sql en
// Supabase (New snippet) — crea la tabla enriquecimientos y las
// columnas suplemento_hoy, bano_tipo y dental_tipo.
//
// Cinco mejoras del registro diario en un paquete:
//
// 1) PREVENCIÓN: nuevo item "🌿 Suplemento" (toggle simple).
//
// 2) ALIMENTACIÓN — botón fusionado: "🥣 Cambio o prueba de alimento"
//    reemplaza a los dos botones anteriores. Al marcarlo, mini-modal:
//    "¿Fue un cambio definitivo o solo una prueba?" — y según eso se
//    llena cambio_alimento o probo_alimento_nuevo (las columnas de
//    siempre, historial y rutinas intactos).
//
// 3) 🛁 BAÑO — mini-modal con tipo:
//    ○ Baño regular / estético  ○ Shampoo dermatológico  ○ Shampoo en seco
//    + "¿También lo cepillaste?". Desaparecen los botones "Shampoo en
//    seco" (ahora tipo de baño) y "Lo peiné" (ahora pregunta del baño).
//    Compatibilidad: los booleanos históricos se siguen llenando
//    (se_bano, shampoo_seco, peino) para que las Rutinas de Análisis
//    no pierdan continuidad; el detalle queda en bano_tipo. Un baño
//    dermatológico también marca tratamiento_dermatologico.
//
// 4) 🦷 LIMPIEZA DENTAL — mini-modal: ○ Cepillado dental ○ Destartraje
//    profesional. El detalle queda en dental_tipo.
//
// 5) 🧠 ENRIQUECIMIENTO Y ENTRENAMIENTO — grupo nuevo, SOLO PERROS por
//    ahora (la versión felina se evaluará más adelante). 7 actividades:
//    🧩 Juguete interactivo · 👃 Juegos de olfato · 🎾 Juego activo ·
//    🎓 Entrenamiento · 🐶 Socializó con otros animales · 👨‍👩‍👧‍👦 Socializó
//    con personas nuevas · 🌳 Exploró un lugar nuevo.
//    Cada actividad abre un mini-modal con duración opcional (5 min,
//    15 min, 30 min, 1 hora, más de 1 hora) y observación opcional.
//    Se guardan en la tabla nueva enriquecimientos (una fila por
//    actividad por día) — la base para las estadísticas futuras:
//    frecuencia mensual, actividad favorita, tiempo promedio, días sin
//    estimulación y tendencias por tipo.
//
// Mismo estilo visual que el resto del registro (grupos colapsables,
// chips, mini-modales bottom-sheet). Al editar un día ya guardado,
// todo se reconstruye: tipo de baño, cepillado, tipo de limpieza
// dental, si el alimento fue prueba o cambio, y las actividades de
// enriquecimiento con sus duraciones y notas.
//
// Uso:
//   1) SQL primero: sql_260_enriquecimiento_y_cuidados.sql → Run
//   2) node generar_260_enriquecimiento_y_cuidados.js
//   3) git add . && commit && push

const fs2 = require('fs')
const path = require('path')

const archivos = [
  {
    ruta: "app/registro-diario/page.tsx",
    base64: "",
    png: false
  },
  {
    ruta: "public/chiqui/chiqui_juguetes.png",
    base64: "",
    png: true
  },
]

let errores = 0
for (const a of archivos) {
  try {
    const rutaCompleta = path.join(process.cwd(), a.ruta)
    fs2.mkdirSync(path.dirname(rutaCompleta), { recursive: true })
    const contenido = Buffer.from(a.base64, 'base64')
    if (a.png) { fs2.writeFileSync(rutaCompleta, contenido) }
    else { fs2.writeFileSync(rutaCompleta, contenido.toString('utf8'), 'utf8') }
    console.log('OK: ' + a.ruta)
  } catch (e) {
    errores++
    console.error('ERROR escribiendo ' + a.ruta + ': ' + e.message)
  }
}

if (errores === 0) {
  console.log('\nListo. 1 archivo de código + 1 imagen.')
  console.log('Recuerda: SQL primero, luego git add / commit / push.')
} else {
  console.error('\nTerminó con ' + errores + ' error(es). NO hagas push.')
  process.exit(1)
}
